# Category: command_injection

class ImagesController < ApplicationController
  def process_image
    @image = params[:image]
    format = params[:format]
    width = params[:width].to_i
    height = params[:height].to_i

    command = "convert #{params[:image]} -resize #{width}x#{height} -format #{format} output.#{format}"
    system(command)

    render text: 'Image processed successfully'
  end
end